import java.nio.ByteBuffer;

public class UTF8Decoder {

    /**
     * Decodifica octetos a caracteres utilizando la decodificación UTF-8 y agrega los caracteres a un StringBuffer.
     * @return el índice del siguiente carácter no verificado en la cadena para decodificar
     */
    private static int decodeOctets(int i, ByteBuffer bb, StringBuilder sb) {
        int b1 = bb.get(i) & 0xFF;

        // Single byte character (ASCII)
        if (b1 <= 0x7F) {
            sb.append((char)b1);
            return i + 1;
        }

        // 2-byte sequence
        if ((b1 & 0xE0) == 0xC0) {
            if (i + 1 >= bb.limit()) {
                throw new IllegalArgumentException("Invalid UTF-8 sequence");
            }
            int b2 = bb.get(i + 1) & 0xFF;
            if ((b2 & 0xC0) != 0x80) {
                throw new IllegalArgumentException("Invalid UTF-8 sequence");
            }
            int ch = ((b1 & 0x1F) << 6) | (b2 & 0x3F);
            sb.append((char)ch);
            return i + 2;
        }

        // 3-byte sequence  
        if ((b1 & 0xF0) == 0xE0) {
            if (i + 2 >= bb.limit()) {
                throw new IllegalArgumentException("Invalid UTF-8 sequence");
            }
            int b2 = bb.get(i + 1) & 0xFF;
            int b3 = bb.get(i + 2) & 0xFF;
            if ((b2 & 0xC0) != 0x80 || (b3 & 0xC0) != 0x80) {
                throw new IllegalArgumentException("Invalid UTF-8 sequence");
            }
            int ch = ((b1 & 0x0F) << 12) | ((b2 & 0x3F) << 6) | (b3 & 0x3F);
            sb.append((char)ch);
            return i + 3;
        }

        // 4-byte sequence
        if ((b1 & 0xF8) == 0xF0) {
            if (i + 3 >= bb.limit()) {
                throw new IllegalArgumentException("Invalid UTF-8 sequence");
            }
            int b2 = bb.get(i + 1) & 0xFF;
            int b3 = bb.get(i + 2) & 0xFF;
            int b4 = bb.get(i + 3) & 0xFF;
            if ((b2 & 0xC0) != 0x80 || (b3 & 0xC0) != 0x80 || (b4 & 0xC0) != 0x80) {
                throw new IllegalArgumentException("Invalid UTF-8 sequence");
            }
            int ch = ((b1 & 0x07) << 18) | ((b2 & 0x3F) << 12) | ((b3 & 0x3F) << 6) | (b4 & 0x3F);
            // Convert to surrogate pair for characters outside BMP
            sb.append(Character.highSurrogate(ch));
            sb.append(Character.lowSurrogate(ch));
            return i + 4;
        }

        throw new IllegalArgumentException("Invalid UTF-8 sequence");
    }
}

import java.util.ArrayList;
import java.util.List;

public class StackMapFrameVisitor {
    private Frame currentFrame;
    private List<Frame> frames;

    public StackMapFrameVisitor() {
        frames = new ArrayList<>();
    }

    private static class Frame {
        int offset;
        int numLocal;
        int numStack;
        int currentIndex;

        Frame(int offset, int numLocal, int numStack) {
            this.offset = offset;
            this.numLocal = numLocal; 
            this.numStack = numStack;
            this.currentIndex = 0;
        }
    }

    int visitFrameStart(final int offset, final int numLocal, final int numStack) {
        currentFrame = new Frame(offset, numLocal, numStack);
        frames.add(currentFrame);
        return currentFrame.currentIndex;
    }
}

import java.util.Arrays;

public class ByteVector {
    private byte[] buffer;
    private int position;
    private static final int DEFAULT_CAPACITY = 32;

    public ByteVector() {
        buffer = new byte[DEFAULT_CAPACITY];
        position = 0;
    }

    /**
     * Aumenta este vector de bytes para que pueda recibir una cantidad adicional de bytes definida por el argumento 'size'.
     * @param size número de bytes adicionales que este vector de bytes debería poder recibir.
     */
    private void enlarge(final int size) {
        int newCapacity = Math.max(buffer.length * 2, buffer.length + size);
        buffer = Arrays.copyOf(buffer, newCapacity);
    }
}

