import java.util.Objects;

public class BinarySearchTree<T extends Comparable<T>> {

    private class TreeNode<T> {
        T data;
        TreeNode<T> left;
        TreeNode<T> right;

        TreeNode(T data) {
            this.data = data;
            this.left = null;
            this.right = null;
        }
    }

    /** 
     * Realiza una rotación a la derecha de un nodo.
     * @param node un nodo a rotar
     * @return un nuevo padre del {@code node}
     */
    private TreeNode<T> rotateRight(TreeNode<T> node) {
        if (node == null || node.left == null) {
            return node;
        }

        TreeNode<T> newParent = node.left;
        node.left = newParent.right;
        newParent.right = node;

        return newParent;
    }
}

import java.io.File;
import java.net.URL;
import java.util.Vector;

public class ClassPathUtils {

    /** 
     * Agrega todos los archivos jar de un directorio al classpath, representado como un Vector de URLs.
     */
    @SuppressWarnings("unchecked")
    public static void addToClassPath(Vector<URL> cpV, String dir) {
        File directory = new File(dir);

        if (!directory.exists() || !directory.isDirectory()) {
            return;
        }

        File[] files = directory.listFiles();
        if (files != null) {
            for (File file : files) {
                if (file.isFile() && file.getName().toLowerCase().endsWith(".jar")) {
                    try {
                        URL jarUrl = file.toURI().toURL();
                        if (!cpV.contains(jarUrl)) {
                            cpV.add(jarUrl);
                        }
                    } catch (Exception e) {
                        e.printStackTrace();
                    }
                }
            }
        }
    }
}

import org.apache.log4j.spi.LoggingEvent;
import java.text.SimpleDateFormat;
import java.util.Date;

public class CustomLogFormatter {

    public String format(LoggingEvent event) {
        StringBuilder formattedMessage = new StringBuilder();

        // Add timestamp
        SimpleDateFormat dateFormat = new SimpleDateFormat("yyyy-MM-dd HH:mm:ss,SSS");
        String timestamp = dateFormat.format(new Date(event.getTimeStamp()));
        formattedMessage.append(timestamp);

        // Add log level
        formattedMessage.append(" [");
        formattedMessage.append(event.getLevel().toString());
        formattedMessage.append("] ");

        // Add logger name
        formattedMessage.append(event.getLoggerName());
        formattedMessage.append(" - ");

        // Add message
        formattedMessage.append(event.getRenderedMessage());

        // Add throwable if exists
        String[] throwableStrRep = event.getThrowableStrRep();
        if (throwableStrRep != null) {
            formattedMessage.append("\n");
            for (String throwableLine : throwableStrRep) {
                formattedMessage.append(throwableLine);
                formattedMessage.append("\n");
            }
        }

        // Add new line
        formattedMessage.append("\n");

        return formattedMessage.toString();
    }
}

