package org.apache.commons.io;

/**
 * Utility class for file operations.
 */
public class FilenameUtils {

    /** The Unix separator character. */
    private static final char UNIX_SEPARATOR = '/';

    /** The Windows separator character. */
    private static final char WINDOWS_SEPARATOR = '\\';

    /** 
     * Devuelve el índice del último carácter separador de directorio. <p> 
     * Este método manejará un archivo en formato Unix o Windows. Se devuelve la posición 
     * de la última barra inclinada o barra invertida. <p> La salida será la misma 
     * independientemente de la máquina en la que se ejecute el código.
     * 
     * @param filename  el nombre del archivo en el que se busca el último separador de ruta, 
     *                 null devuelve -1
     * @return el índice del último carácter separador, o -1 si no existe tal carácter
     */
    public static int indexOfLastSeparator(String filename) {
        if (filename == null) {
            return -1;
        }

        int lastUnixPos = filename.lastIndexOf(UNIX_SEPARATOR);
        int lastWindowsPos = filename.lastIndexOf(WINDOWS_SEPARATOR);

        return Math.max(lastUnixPos, lastWindowsPos);
    }
}

import java.util.Arrays;

public class HeaderParser {

    /**
     * Omite bytes hasta el final de la línea actual.
     * @param headerPart Las cabeceras que se están analizando.
     * @param end Índice del último byte que aún no ha sido procesado.
     * @return Índice de la secuencia \r\n, que indica el final de la línea.
     */
    private int parseEndOfLine(String headerPart, int end) {
        int index = end;

        // Buscar hasta encontrar \r\n o llegar al final
        while (index < headerPart.length() - 1) {
            if (headerPart.charAt(index) == '\r' && 
                headerPart.charAt(index + 1) == '\n') {
                return index;
            }
            index++;
        }

        // Si no se encuentra \r\n, devolver el final del string
        return headerPart.length() - 1;
    }
}

