        this.logTable = logTable;
    }

    /**
     * Agrega un mensaje de registro a ser mostrado en la "LogTable". 
     * Este método es seguro para hilos ya que envía solicitudes al SwingThread 
     * en lugar de procesarlas directamente.
     */
    public void addMessage(final LogRecord lr) {
        if (lr == null) {
            return;
        }

        SwingUtilities.invokeLater(new Runnable() {
            @Override
            public void run() {
                logTable.addRow(lr);
            }
        });
    }
}

import java.util.*;
import org.jgrapht.*;

public class BipartiteGraphGenerator<V,E> implements GraphGenerator<V,E,V> {
    private int n1; // number of vertices in first partition
    private int n2; // number of vertices in second partition

    public BipartiteGraphGenerator(int n1, int n2) {
        this.n1 = n1;
        this.n2 = n2;
    }

    @Override
    public void generateGraph(Graph<V,E> target, Map<String,V> resultMap) {
        // Create vertices for first partition
        List<V> partition1 = new ArrayList<>();
        for(int i = 0; i < n1; i++) {
            V vertex = target.vertexSupplier().get();
            target.addVertex(vertex);
            partition1.add(vertex);
            if(resultMap != null) {
                resultMap.put("P1_" + i, vertex);
            }
        }

        // Create vertices for second partition  
        List<V> partition2 = new ArrayList<>();
        for(int i = 0; i < n2; i++) {
            V vertex = target.vertexSupplier().get();
            target.addVertex(vertex);
            partition2.add(vertex);
            if(resultMap != null) {
                resultMap.put("P2_" + i, vertex);
            }
        }

        // Add edges between all vertices in partition1 and partition2
        for(V v1 : partition1) {
            for(V v2 : partition2) {
                target.addEdge(v1, v2);
            }
        }
    }
}

import java.io.ByteArrayOutputStream;

public class ByteBuffer {
    private byte[] buffer;

    /**
     * Busca un byte de valor especificado en el <code>buffer</code>, comenzando en la <code>posición</code> especificada.
     * @param value El valor a encontrar.
     * @param pos   La posición inicial para la búsqueda.
     * @return La posición del byte encontrado, contando desde el inicio del <code>buffer</code>, o <code>-1</code> si no se encuentra.
     */
    protected int findByte(byte value, int pos) {
        if (buffer == null || pos < 0 || pos >= buffer.length) {
            return -1;
        }

        for (int i = pos; i < buffer.length; i++) {
            if (buffer[i] == value) {
                return i;
            }
        }

        return -1;
    }
}

import com.dyuproject.protostuff.LinkedBuffer;
import com.dyuproject.protostuff.Schema;
import com.dyuproject.protostuff.ProtobufOutput;
import java.io.IOException;
import java.io.OutputStream;

public class MessageSerializer {

    /**
     * Serializa el {@code message},precedido por su longitud, en un {@link OutputStream}.
     * @return el tamaño del mensaje
     */
    public static <T> int writeDelimitedTo(OutputStream out, T message, Schema<T> schema, LinkedBuffer buffer) throws IOException {
        // Create protobuf output with the buffer
        ProtobufOutput output = new ProtobufOutput(buffer);

        // Serialize the message to get its size
        schema.writeTo(output, message);

        // Get the serialized size
        int size = output.getSize();

        // Write the size as a varint to the output stream
        while ((size & ~0x7F) != 0) {
            out.write((size & 0x7F) | 0x80);
            size >>>= 7;
        }
        out.write(size);

        // Write the actual message
        LinkedBuffer.writeTo(out, buffer);

        // Clear the buffer
        buffer.clear();

        return output.getSize();
    }
}

