import org.apache.log4j.AppenderSkeleton;
import org.apache.log4j.Layout;
import org.apache.log4j.spi.LoggingEvent;
import java.io.IOException;
import java.io.Writer;

public class CustomAppender extends AppenderSkeleton {

    private Writer writer;

    /** 
     * Este método realiza la escritura
     */
    protected void subAppend(LoggingEvent event) {
        if(layout == null || writer == null) {
            return;
        }

        try {
            String formattedMessage = layout.format(event);
            writer.write(formattedMessage);

            if(layout.ignoresThrowable()) {
                String[] throwableStrRep = event.getThrowableStrRep();
                if (throwableStrRep != null) {
                    for (String line : throwableStrRep) {
                        writer.write(line);
                        writer.write(Layout.LINE_SEP);
                    }
                }
            }

            writer.flush();
        } catch (IOException e) {
            errorHandler.error("Failed to write log event", e, 1);
        }
    }

    @Override
    public void close() {
        if(writer != null) {
            try {
                writer.close();
            } catch (IOException e) {
                // Ignore
            }
        }
    }

    @Override
    public boolean requiresLayout() {
        return true;
    }

    public void setWriter(Writer writer) {
        this.writer = writer;
    }
}

import java.util.ArrayList;
import java.util.List;

public class SymbolTable {
    private List<String> types;

    public SymbolTable() {
        types = new ArrayList<>();
    }

    /**
     * Agrega un tipo en la tabla de tipos de esta tabla de símbolos. No hace nada si la tabla de tipos ya contiene un tipo similar.
     * @param value un nombre de clase interno.
     * @return el índice de un nuevo tipo o de un tipo ya existente con el valor dado.
     */
    public int addType(final String value) {
        // Check if type already exists
        for (int i = 0; i < types.size(); i++) {
            if (types.get(i).equals(value)) {
                return i;
            }
        }

        // Add new type if it doesn't exist
        types.add(value);
        return types.size() - 1;
    }
}

import java.lang.reflect.ParameterizedType;
import java.lang.reflect.Type;
import java.lang.reflect.TypeVariable;
import java.util.HashMap;
import java.util.Map;

public class TypeResolver {

    public static Class<?>[] resolveArguments(Type genericType, Class<?> targetType) {
        if (!(genericType instanceof ParameterizedType)) {
            return null;
        }

        ParameterizedType parameterizedType = (ParameterizedType) genericType;
        Type[] actualTypeArguments = parameterizedType.getActualTypeArguments();
        Class<?>[] resolvedTypes = new Class<?>[actualTypeArguments.length];

        // Map to store type variable mappings
        Map<TypeVariable<?>, Type> typeVariableMap = new HashMap<>();

        // Get type variables from target type
        TypeVariable<?>[] typeParameters = targetType.getTypeParameters();

        // Build mapping of type variables to actual types
        for (int i = 0; i < actualTypeArguments.length && i < typeParameters.length; i++) {
            if (actualTypeArguments[i] instanceof Class) {
                resolvedTypes[i] = (Class<?>) actualTypeArguments[i];
            } else if (actualTypeArguments[i] instanceof TypeVariable) {
                TypeVariable<?> typeVar = (TypeVariable<?>) actualTypeArguments[i];
                Type resolvedType = typeVariableMap.get(typeVar);
                if (resolvedType instanceof Class) {
                    resolvedTypes[i] = (Class<?>) resolvedType;
                } else {
                    // If we can't resolve the type variable, return null
                    return null;
                }
            } else {
                // If we encounter other type of Type, return null
                return null;
            }
        }

        return resolvedTypes;
    }
}

import java.util.Objects;
import java.util.concurrent.atomic.AtomicReference;

public class MetricsCache<METRICS> {

    private AtomicReference<METRICS> cache;

    public MetricsCache() {
        this.cache = new AtomicReference<>();
    }

    /**
     * Acepta los datos en la caché y los combina con el valor existente. Este método no es seguro para hilos, se debe evitar la llamada concurrente.
     * @param data que se va a agregar potencialmente.
     */
    @Override 
    public void accept(final METRICS data) {
        Objects.requireNonNull(data, "Data cannot be null");

        METRICS currentValue = cache.get();
        if (currentValue == null) {
            cache.set(data);
        } else {
            // Si hay un valor existente, combinar los datos
            try {
                if (data instanceof Mergeable) {
                    ((Mergeable)currentValue).merge(data);
                } else {
                    // Si no es mergeable, simplemente reemplazar
                    cache.set(data);
                }
            } catch (Exception e) {
                // En caso de error al combinar, mantener el valor actual
                // y registrar el error
                System.err.println("Error merging metrics data: " + e.getMessage());
            }
        }
    }
}

// Interfaz opcional para objetos que pueden combinarse
interface Mergeable<T> {
    void merge(T other);
}

import java.util.Objects;

public class Bucket {
    private Bucket prev;
    private Bucket next;

    /**
     * Inserta este "bucket" en la estructura de datos antes del {@code bucket}.
     * @param bucket el "bucket", que será el siguiente a este "bucket".
     */
    public void insertBefore(Bucket bucket) {
        Objects.requireNonNull(bucket, "bucket cannot be null");

        // Set this bucket's next reference to the given bucket
        this.next = bucket;

        // Set this bucket's prev reference to the given bucket's previous
        this.prev = bucket.prev;

        // Update the given bucket's prev reference to point to this bucket
        bucket.prev = this;

        // If there was a previous bucket, update its next reference
        if (this.prev != null) {
            this.prev.next = this;
        }
    }
}

