import java.io.File;

public class ConfigurationManager {

    /**
     * Crea el directorio donde se escribirá la lista de archivos MRU. El directorio "lf5" se crea en el directorio de Documentos y Configuraciones en máquinas con Windows 2000 y donde sea que apunte la variable user.home en todas las demás plataformas.
     */
    public static void createConfigurationDirectory() {
        String userHome = System.getProperty("user.home");
        String fileSeparator = System.getProperty("file.separator");
        String configDirPath = userHome + fileSeparator + "lf5";

        File configDir = new File(configDirPath);

        if (!configDir.exists()) {
            boolean created = configDir.mkdir();
            if (!created) {
                throw new RuntimeException("No se pudo crear el directorio de configuración en: " + configDirPath);
            }
        }
    }
}

import org.objectweb.asm.ClassReader;
import org.objectweb.asm.Attribute;

public class CustomClassReader extends ClassReader {

    public CustomClassReader(byte[] classFile) {
        super(classFile);
    }

    /**
     * Lee un valor long con signo en este {@link ClassReader}. <i>Este método está destinado a subclases de {@link Attribute},
     * y normalmente no es necesario para generadores de clases o adaptadores.</i>
     * @param offset el desplazamiento inicial del valor a leer en este {@link ClassReader}.
     * @return el valor leído.
     */
    public long readLong(final int offset) {
        byte[] classFileBuffer = this.b;
        return (((long)classFileBuffer[offset] & 0xFF) << 56)
            | (((long)classFileBuffer[offset + 1] & 0xFF) << 48)
            | (((long)classFileBuffer[offset + 2] & 0xFF) << 40)
            | (((long)classFileBuffer[offset + 3] & 0xFF) << 32)
            | (((long)classFileBuffer[offset + 4] & 0xFF) << 24)
            | (((long)classFileBuffer[offset + 5] & 0xFF) << 16)
            | (((long)classFileBuffer[offset + 6] & 0xFF) << 8)
            | ((long)classFileBuffer[offset + 7] & 0xFF);
    }
}

import java.util.Arrays;

public class ByteArrayMatcher {

    private byte[] pattern; // Internal array to compare against

    /**
     * Devuelve verdadero si el contenido del array interno y el array proporcionado coinciden.
     */
    public boolean equals(final byte[] data, int offset, final int len) {
        if (data == null || pattern == null) {
            return false;
        }

        if (offset < 0 || len < 0) {
            return false;
        }

        if (offset + len > data.length || len != pattern.length) {
            return false;
        }

        for (int i = 0; i < len; i++) {
            if (pattern[i] != data[offset + i]) {
                return false;
            }
        }

        return true;
    }

    // Constructor to initialize the internal pattern
    public ByteArrayMatcher(byte[] pattern) {
        this.pattern = pattern;
    }
}

import java.util.Objects;

public class ArrayUtils {

    /**
     * Empty array constant used for optimization
     */
    public static final Byte[] EMPTY_BYTE_OBJECT_ARRAY = new Byte[0];

    /**
     * <p>Técnica de programación defensiva para cambiar una referencia <code>null</code> por una vacía.</p>
     * <p>Este método devuelve un array vacío para un array de entrada <code>null</code>.</p>
     * <p>Como técnica de optimización de memoria, un array vacío pasado se sobrescribirá con las referencias vacías <code>public static</code> en esta clase.</p>
     * @param array  el array a verificar si es <code>null</code> o vacío
     * @return el mismo array, un array vacío <code>public static</code> si la entrada es <code>null</code> o vacía
     * @since 2.5
     */
    public static Byte[] nullToEmpty(final Byte[] array) {
        if (array == null || array.length == 0) {
            return EMPTY_BYTE_OBJECT_ARRAY;
        }
        return array;
    }
}

import java.io.IOException;
import java.io.PrintWriter;
import java.net.Socket;
import java.util.ArrayList;
import java.util.List;

public class TelnetServer {
    private List<PrintWriter> clientWriters;

    public TelnetServer() {
        clientWriters = new ArrayList<>();
    }

    /**
     * Envía un mensaje a cada uno de los clientes en un formato compatible con telnet.
     */
    public synchronized void send(final String message) {
        // Agregar retorno de carro y nueva línea para compatibilidad telnet
        String telnetMessage = message + "\r\n";

        // Iterar sobre la lista de writers de clientes
        List<PrintWriter> disconnectedClients = new ArrayList<>();

        for (PrintWriter writer : clientWriters) {
            try {
                writer.print(telnetMessage);
                writer.flush();
            } catch (Exception e) {
                // Si hay error al escribir, agregar cliente a lista de desconectados
                disconnectedClients.add(writer);
            }
        }

        // Remover clientes desconectados
        clientWriters.removeAll(disconnectedClients);
    }

    // Método para agregar un nuevo cliente
    public synchronized void addClient(Socket clientSocket) throws IOException {
        PrintWriter writer = new PrintWriter(clientSocket.getOutputStream(), true);
        clientWriters.add(writer);
    }
}

