import org.apache.log4j.spi.LoggingEvent;

public class CircularBuffer {
    private LoggingEvent[] buffer;
    private int head = 0;
    private int tail = 0;
    private int size = 0;
    private int maxSize;

    public CircularBuffer(int maxSize) {
        this.maxSize = maxSize;
        buffer = new LoggingEvent[maxSize];
    }

    /**
     * Coloca un {@link LoggingEvent} en el búfer. Si el búfer está lleno, el evento es 
     * <b>silenciosamente descartado</b>. Es responsabilidad del llamador asegurarse de 
     * que el búfer tenga espacio libre.
     */
    public void put(LoggingEvent o) {
        if (size < maxSize) {
            buffer[tail] = o;
            tail = (tail + 1) % maxSize;
            size++;
        }
        // Si el buffer está lleno, el evento se descarta silenciosamente
    }
}

import java.util.ArrayList;
import java.util.List;

public class TimeRangeBuilder {

    private static final long FETCH_DATA_DURATION = 24 * 60 * 60 * 1000; // 24 hours in milliseconds

    /**
     * Divide los rangos de tiempo para asegurar que el tiempo de inicio y el tiempo de finalización sean menores que {@link #FETCH_DATA_DURATION}
     */
    protected List<TimeRange> construirRangosDeTiempo(long inicio, long fin) {
        List<TimeRange> rangos = new ArrayList<>();

        while (inicio < fin) {
            long rangoFin = Math.min(inicio + FETCH_DATA_DURATION, fin);
            rangos.add(new TimeRange(inicio, rangoFin));
            inicio = rangoFin;
        }

        return rangos;
    }

    // Inner class to represent a time range
    protected static class TimeRange {
        private final long inicio;
        private final long fin;

        public TimeRange(long inicio, long fin) {
            this.inicio = inicio;
            this.fin = fin;
        }

        public long getInicio() {
            return inicio;
        }

        public long getFin() {
            return fin;
        }
    }
}

