import java.util.Stack;

public class MethodFrameHandler {
    private Stack<Object> operandStack;

    /**
     * Extrae tantos tipos abstractos de la pila de marcos de salida como lo describe el descriptor dado.
     * @param descriptor un tipo o descriptor de método (en cuyo caso se extraen sus tipos de argumento).
     */
    private void pop(final String descriptor) {
        String desc = descriptor;

        // Si es un descriptor de método, extraer solo los argumentos
        if (descriptor.charAt(0) == '(') {
            desc = descriptor.substring(1, descriptor.indexOf(')'));
        }

        int index = 0;
        while (index < desc.length()) {
            char c = desc.charAt(index);

            switch (c) {
                case 'B': // byte
                case 'C': // char
                case 'I': // int
                case 'S': // short
                case 'Z': // boolean
                case 'F': // float
                    operandStack.pop();
                    index++;
                    break;

                case 'J': // long
                case 'D': // double
                    operandStack.pop();
                    index++;
                    break;

                case 'L': // Object reference
                    operandStack.pop();
                    index = desc.indexOf(';', index) + 1;
                    break;

                case '[': // Array
                    int dimensions = 0;
                    while (desc.charAt(index) == '[') {
                        dimensions++;
                        index++;
                    }
                    if (desc.charAt(index) == 'L') {
                        index = desc.indexOf(';', index) + 1;
                    } else {
                        index++;
                    }
                    operandStack.pop();
                    break;

                default:
                    throw new IllegalArgumentException("Invalid descriptor: " + descriptor);
            }
        }
    }
}

import java.io.IOException;
import java.io.OutputStream;

public class ByteOutputStream extends OutputStream {

    private byte[] buffer;
    private int count;

    public ByteOutputStream() {
        buffer = new byte[32];
        count = 0;
    }

    @Override
    public void write(final byte b[], final int off, final int len) throws IOException {
        if (b == null) {
            throw new NullPointerException();
        }

        if (off < 0 || len < 0 || off + len > b.length) {
            throw new IndexOutOfBoundsException();
        }

        // Ensure capacity
        ensureCapacity(count + len);

        // Copy bytes to internal buffer
        System.arraycopy(b, off, buffer, count, len);
        count += len;
    }

    private void ensureCapacity(int minCapacity) {
        // If buffer is too small, grow it
        if (minCapacity > buffer.length) {
            int newCapacity = Math.max(buffer.length << 1, minCapacity);
            byte[] newBuffer = new byte[newCapacity];
            System.arraycopy(buffer, 0, newBuffer, 0, count);
            buffer = newBuffer;
        }
    }

    @Override
    public void write(int b) throws IOException {
        ensureCapacity(count + 1);
        buffer[count] = (byte) b;
        count++;
    }
}

public class ArrayUtils {
    /**
     * Intercambia los dos elementos en los índices especificados en el arreglo dado.
     * @param <V> el tipo de elementos en el arreglo
     * @param arr el arreglo
     * @param i el índice del primer elemento
     * @param j el índice del segundo elemento
     */
    public static final <V> void swap(V[] arr, int i, int j) {
        V temp = arr[i];
        arr[i] = arr[j];
        arr[j] = temp;
    }
}

