public class ArrayUtils {
    /**
     * Este método crea una copia del array proporcionado y asegura que todas las cadenas 
     * en el nuevo array contengan solo letras minúsculas.
     * Utilizar este método para copiar arrays de cadenas significa que los cambios en el 
     * array src no modifican el array dst.
     * @param src Array origen que se desea copiar
     * @return Nuevo array con las cadenas en minúsculas
     */
    private static String[] copiarCadenas(final String[] src) {
        if (src == null) {
            return null;
        }

        String[] dst = new String[src.length];
        for (int i = 0; i < src.length; i++) {
            if (src[i] != null) {
                dst[i] = src[i].toLowerCase();
            }
        }
        return dst;
    }
}

import java.util.Objects;

public class BoxSplitter {

    public static class Box2D {
        private final double minX;
        private final double maxX; 
        private final double minY;
        private final double maxY;

        public Box2D(double minX, double maxX, double minY, double maxY) {
            this.minX = minX;
            this.maxX = maxX;
            this.minY = minY;
            this.maxY = maxY;
        }
    }

    public static class Pair<T,U> {
        private final T first;
        private final U second;

        public Pair(T first, U second) {
            this.first = first;
            this.second = second;
        }
    }

    /** 
     * Divide una caja a lo largo del eje x en dos cajas iguales.
     * @param box la caja a dividir
     * @return un par con las dos cajas resultantes
     */
    public static Pair<Box2D,Box2D> splitAlongXAxis(Box2D box) {
        Objects.requireNonNull(box, "Box cannot be null");

        double midX = (box.minX + box.maxX) / 2.0;

        Box2D leftBox = new Box2D(box.minX, midX, box.minY, box.maxY);
        Box2D rightBox = new Box2D(midX, box.maxX, box.minY, box.maxY);

        return new Pair<>(leftBox, rightBox);
    }
}

import java.util.Arrays;

public class ByteVector {
    private byte[] buffer;
    private int position;
    private static final int DEFAULT_CAPACITY = 32;

    public ByteVector() {
        buffer = new byte[DEFAULT_CAPACITY];
        position = 0;
    }

    /**
     * Aumenta este vector de bytes para que pueda recibir una cantidad adicional de bytes definida por el argumento 'size'. 
     * @param size número de bytes adicionales que este vector de bytes debería poder recibir.
     */
    private void enlarge(final int size) {
        int newCapacity = buffer.length;

        // Calculate new capacity needed
        while (position + size > newCapacity) {
            newCapacity = newCapacity * 2;
        }

        // Only resize if needed
        if (newCapacity > buffer.length) {
            buffer = Arrays.copyOf(buffer, newCapacity);
        }
    }
}

import org.apache.log4j.Appender;
import java.util.Enumeration;

public class Logger {
    private AppenderList appenderList;

    /**
     * Devuelve <code>true</code> si el "appender" especificado está en la lista de "appenders" adjuntos, <code>false</code> en caso contrario.
     * @since 1.2
     */
    public boolean isAttached(Appender appender) {
        if (appender == null || appenderList == null) {
            return false;
        }

        Enumeration<Appender> appenders = appenderList.getAllAppenders();
        while (appenders.hasMoreElements()) {
            Appender currentAppender = appenders.nextElement();
            if (currentAppender == appender) {
                return true;
            }
        }
        return false;
    }
}

import java.util.Comparator;

public class DoubleComparator implements Comparator<Double> {

    /** 
     * Compara dos valores de punto flotante. Devuelve 0 si son iguales, -1 si {@literal o1 < o2},1 en caso contrario.
     * @param o1 el primer valor
     * @param o2 el segundo valor
     * @return 0 si son iguales, -1 si {@literal o1 < o2},1 en caso contrario
     */
    @Override
    public int compare(Double o1, Double o2) {
        if (o1.equals(o2)) {
            return 0;
        }
        return o1 < o2 ? -1 : 1;
    }
}

