import java.beans.Introspector;

public class StringUtils {
    /**
     * Inverso de Introspector.decapitalize
     */
    public static String capitalize(String name) {
        if (name == null || name.length() == 0) {
            return name;
        }
        if (name.length() > 1 && Character.isUpperCase(name.charAt(1)) &&
                Character.isUpperCase(name.charAt(0))) {
            return name;
        }
        char chars[] = name.toCharArray();
        chars[0] = Character.toUpperCase(chars[0]);
        return new String(chars);
    }
}

import java.io.DataOutput;
import java.io.IOException;

public class BufferWriter {
    /**
     * Escribe el contenido del {@link LinkedBuffer} en el {@link DataOutput}.
     * @return el tamaño total del contenido del búfer.
     */
    public static int writeTo(final DataOutput out, LinkedBuffer node) throws IOException {
        int totalSize = 0;

        while (node != null && node.buffer != null) {
            if (node.offset > 0) {
                out.write(node.buffer, 0, node.offset);
                totalSize += node.offset;
            }
            node = node.next;
        }

        return totalSize;
    }

    // LinkedBuffer class for compilation
    private static class LinkedBuffer {
        byte[] buffer;
        int offset;
        LinkedBuffer next;
    }
}

public class BooleanUtils {
    /**
     * <p>Verifica si un valor <code>Boolean</code> <i>no</i> es <code>true</code>, 
     * manejando <code>null</code> al devolver <code>true</code>.</p>
     *
     * <pre>
     * BooleanUtils.isNotTrue(Boolean.TRUE)  = false
     * BooleanUtils.isNotTrue(Boolean.FALSE) = true
     * BooleanUtils.isNotTrue(null)          = true
     * </pre>
     *
     * @param bool  el booleano a verificar, null devuelve <code>true</code>
     * @return <code>true</code> si la entrada es null o false
     * @since 2.3
     */
    public static boolean isNotTrue(Boolean bool) {
        return !Boolean.TRUE.equals(bool);
    }
}

import java.util.LinkedList;

public class Queue<T> {
    private LinkedList<T> elements;

    public Queue() {
        elements = new LinkedList<>();
    }

    public String toString() {
        if (elements.isEmpty()) {
            return "[]";
        }

        StringBuilder sb = new StringBuilder();
        sb.append("[");

        for (T element : elements) {
            sb.append(element);
            sb.append(", ");
        }

        // Remove last comma and space
        sb.setLength(sb.length() - 2);
        sb.append("]");

        return sb.toString();
    }
}

