    }
}

import java.util.Collection;

public class CollectionUtils {

    /**
     * Devuelve el primer elemento en '<code>candidates</code>' que se encuentra en '<code>source</code>'. 
     * Si no hay ningún elemento en '<code>candidates</code>' presente en '<code>source</code>', devuelve <code>null</code>. 
     * El orden de iteración es específico de la implementación de {@link Collection}.
     * @param source la colección fuente
     * @param candidates los candidatos a buscar
     * @return el primer objeto presente, o <code>null</code> si no se encuentra
     */
    public static Object findFirstMatch(Collection source, Collection candidates) {
        if (source == null || candidates == null) {
            return null;
        }

        for (Object candidate : candidates) {
            if (source.contains(candidate)) {
                return candidate;
            }
        }

        return null;
    }
}

public class StringUtils {
    /**
     * Elimina los espacios en blanco al final del String dado.
     * @param str el String a verificar
     * @return el String sin espacios en blanco al final
     * @see java.lang.Character#isWhitespace
     */
    public static String trimTrailingWhitespace(String str) {
        if (str == null) {
            return null;
        }

        int len = str.length();

        while (len > 0 && Character.isWhitespace(str.charAt(len - 1))) {
            len--;
        }

        return str.substring(0, len);
    }
}

import java.io.File;
import java.io.IOException;
import java.util.logging.Logger;
import java.util.logging.Level;

public class ConfigurationManager {
    private static final Logger LOGGER = Logger.getLogger(ConfigurationManager.class.getName());
    private static final String DISTRIBUTION_PATH = "dist/";

    /**
     * inicializa la configuración, como verificar la ruta de distribución
     */
    public void init() {
        try {
            // Verificar si existe el directorio de distribución
            File distributionDir = new File(DISTRIBUTION_PATH);

            if (!distributionDir.exists()) {
                // Crear el directorio si no existe
                if (distributionDir.mkdirs()) {
                    LOGGER.info("Directorio de distribución creado exitosamente");
                } else {
                    LOGGER.severe("No se pudo crear el directorio de distribución");
                }
            }

            // Verificar permisos de escritura
            if (!distributionDir.canWrite()) {
                LOGGER.warning("El directorio de distribución no tiene permisos de escritura");
            }

            // Otras inicializaciones de configuración pueden ir aquí

        } catch (SecurityException e) {
            LOGGER.log(Level.SEVERE, "Error de seguridad al inicializar la configuración", e);
        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Error al inicializar la configuración", e);
        }
    }
}

import java.io.IOException;
import java.io.DataInputStream;

public class DataReader {
    private DataInputStream input;

    public DataReader(DataInputStream input) {
        this.input = input;
    }

    /** 
     * Lee el valor de un campo de tipo {@code string} del flujo.
     */
    @Override
    public String readString() throws IOException {
        // Read the string length first
        int length = input.readInt();

        if (length < 0) {
            return null;
        }

        // Create byte array to hold string data
        byte[] bytes = new byte[length];

        // Read the string bytes
        input.readFully(bytes);

        // Convert bytes to string using UTF-8 encoding
        return new String(bytes, "UTF-8");
    }
}

public class DigitConverter {
    /**
     * Interpreta un carácter como un dígito (en cualquier base hasta 36) y devuelve el valor numérico. 
     * Esto es similar a {@code Character.digit()} pero no aceptamos dígitos no ASCII.
     */
    private static int valorDígito(final char c) {
        if (c >= '0' && c <= '9') {
            return c - '0';
        }
        if (c >= 'a' && c <= 'z') {
            return c - 'a' + 10;
        }
        if (c >= 'A' && c <= 'Z') {
            return c - 'A' + 10;
        }
        return -1;
    }
}

import com.google.gson.JsonObject;
import java.util.HashMap;
import java.util.Map;

public class ContentBuilder {

    /**
     * construir contenido, si tiene "ats" alguien establece el "ats"
     */
    private Map<String,Object> buildContent(JsonObject jsonObject) {
        Map<String, Object> content = new HashMap<>();

        if (jsonObject != null) {
            // Iterate through all entries in JsonObject
            for (Map.Entry<String, JsonElement> entry : jsonObject.entrySet()) {
                String key = entry.getKey();
                JsonElement element = entry.getValue();

                // Handle "ats" field specially
                if ("ats".equals(key) && !element.isJsonNull()) {
                    content.put(key, element.getAsString());
                }
                // Handle other fields
                else if (!element.isJsonNull()) {
                    if (element.isJsonPrimitive()) {
                        JsonPrimitive primitive = element.getAsJsonPrimitive();
                        if (primitive.isString()) {
                            content.put(key, primitive.getAsString());
                        } else if (primitive.isNumber()) {
                            content.put(key, primitive.getAsNumber());
                        } else if (primitive.isBoolean()) {
                            content.put(key, primitive.getAsBoolean());
                        }
                    } else if (element.isJsonObject()) {
                        content.put(key, buildContent(element.getAsJsonObject()));
                    } else if (element.isJsonArray()) {
                        content.put(key, element.getAsJsonArray());
                    }
                }
            }
        }

        return content;
    }
}

import org.atmosphere.cpr.AtmosphereFramework;
import org.atmosphere.cpr.AtmosphereHandler;
import org.atmosphere.cpr.AtmosphereConfig;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

public class AtmosphereFrameworkImpl extends AtmosphereFramework {

    private final Map<String, AtmosphereHandler> handlers = new ConcurrentHashMap<>();

    /** 
     * Elimina un {@link AtmosphereHandler}.
     * @param mapping el mapeo utilizado al invocar {@link #addAtmosphereHandler(String,AtmosphereHandler)};
     * @return true si se eliminó
     */
    public AtmosphereFramework removeAtmosphereHandler(String mapping) {
        if (mapping == null) {
            return this;
        }

        String mappingPath = mapping.endsWith("/") ? mapping : mapping + "/";

        if (handlers.containsKey(mappingPath)) {
            handlers.remove(mappingPath);
            return this;
        }

        // Try without trailing slash if not found
        if (handlers.containsKey(mapping)) {
            handlers.remove(mapping);
        }

        return this;
    }
}

