import java.util.HashMap;
import java.util.Map;

public class StringUtils {

    private static final Map<String, String> JAVA_ESCAPES;

    static {
        JAVA_ESCAPES = new HashMap<>();
        JAVA_ESCAPES.put("\\t", "\t");
        JAVA_ESCAPES.put("\\b", "\b");
        JAVA_ESCAPES.put("\\n", "\n");
        JAVA_ESCAPES.put("\\r", "\r");
        JAVA_ESCAPES.put("\\f", "\f");
        JAVA_ESCAPES.put("\\'", "'");
        JAVA_ESCAPES.put("\\\"", "\"");
        JAVA_ESCAPES.put("\\\\", "\\");
    }

    public static String unescapeJava(String str) throws Exception {
        if (str == null) {
            return null;
        }

        StringBuilder result = new StringBuilder(str.length());

        for (int i = 0; i < str.length(); i++) {
            char currentChar = str.charAt(i);

            if (currentChar == '\\' && i + 1 < str.length()) {
                // Check for escaped sequence
                String escape = str.substring(i, i + 2);
                if (JAVA_ESCAPES.containsKey(escape)) {
                    result.append(JAVA_ESCAPES.get(escape));
                    i++; // Skip next character as it's part of escape sequence
                } else if (i + 3 < str.length() && 
                         str.charAt(i + 1) == 'u') {
                    // Handle unicode escape sequences
                    String hex = str.substring(i + 2, i + 6);
                    try {
                        result.append((char) Integer.parseInt(hex, 16));
                        i += 5; // Skip the unicode sequence
                    } catch (NumberFormatException e) {
                        throw new Exception("Invalid unicode escape sequence: \\u" + hex);
                    }
                } else {
                    // Not a recognized escape sequence, keep the backslash
                    result.append(currentChar);
                }
            } else {
                result.append(currentChar);
            }
        }

        return result.toString();
    }
}

import java.nio.charset.Charset;
import java.util.HashMap;
import java.util.Map;

public class CharsetConverter {

    private static final Map<String, String> MIME_TO_JAVA_CHARSET = new HashMap<>();

    static {
        MIME_TO_JAVA_CHARSET.put("ISO-8859-1", "ISO-8859-1");
        MIME_TO_JAVA_CHARSET.put("ISO8859_1", "ISO-8859-1");
        MIME_TO_JAVA_CHARSET.put("ISO-8859-2", "ISO-8859-2"); 
        MIME_TO_JAVA_CHARSET.put("ISO8859_2", "ISO-8859-2");
        MIME_TO_JAVA_CHARSET.put("UTF-8", "UTF-8");
        MIME_TO_JAVA_CHARSET.put("UTF8", "UTF-8");
        MIME_TO_JAVA_CHARSET.put("US-ASCII", "US-ASCII");
        MIME_TO_JAVA_CHARSET.put("ASCII", "US-ASCII");
        MIME_TO_JAVA_CHARSET.put("windows-1252", "windows-1252");
        MIME_TO_JAVA_CHARSET.put("CP1252", "windows-1252");
    }

    private static String javaCharset(String charset) {
        if (charset == null || charset.trim().isEmpty()) {
            return Charset.defaultCharset().name();
        }

        String normalizedCharset = charset.trim().toUpperCase();
        String javaCharset = MIME_TO_JAVA_CHARSET.get(normalizedCharset);

        if (javaCharset != null) {
            return javaCharset;
        }

        try {
            // Verify if the charset is valid by attempting to get an instance
            Charset.forName(charset);
            return charset;
        } catch (Exception e) {
            // If charset is not recognized, return default charset
            return Charset.defaultCharset().name();
        }
    }
}

