import org.objectweb.asm.ClassReader;

public class CustomClassReader extends ClassReader {

    public CustomClassReader(byte[] classFile) {
        super(classFile);
    }

    /**
     * Lee un valor corto con signo en este {@link ClassReader}. <i>Este método está destinado a subclases de {@link Attribute},
     * y normalmente no es necesario para generadores de clases o adaptadores.</i>
     * @param offset el desplazamiento inicial del valor a leer en este {@link ClassReader}.
     * @return el valor leído.
     */
    public short readShort(final int offset) {
        byte[] classFileBuffer = this.b;
        return (short) ((classFileBuffer[offset] << 8) | (classFileBuffer[offset + 1] & 0xFF));
    }
}

import java.lang.reflect.Array;

public class ArrayUtils {

    /**
     * Devuelve una copia del array dado de tamaño 1 mayor que el argumento. El último valor del array se deja con el valor por defecto.
     * @param array El array a copiar, no debe ser <code>null</code>.
     * @param newArrayComponentType Si <code>array</code> es <code>null</code>, crea un array de tamaño 1 de este tipo.
     * @return Una nueva copia del array de tamaño 1 mayor que la entrada.
     */
    private static Object copyArrayGrow1(final Object array, final Class<?> newArrayComponentType) {
        if (array != null) {
            int arrayLength = Array.getLength(array);
            Object newArray = Array.newInstance(array.getClass().getComponentType(), arrayLength + 1);
            System.arraycopy(array, 0, newArray, 0, arrayLength);
            return newArray;
        }
        return Array.newInstance(newArrayComponentType, 1);
    }
}

public class LogCalculator {
    /**
     * Calcula el piso(log_2(n)) + 1
     * @param n numero entero positivo
     * @return piso(log_2(n)) + 1
     */
    public static int log(int n) {
        int count = 0;
        while (n > 1) {
            n = n/2;
            count++;
        }
        return count + 1;
    }
}

import java.util.HashSet;
import java.util.Set;

public class SetOperations<V> {

    /**
     * Método eficiente para calcular la intersección entre dos conjuntos
     * @param set1 conjunto $1$
     * @param set2 conjunto $2$ 
     * @return intersección del conjunto $1$ y $2$
     */
    private Set<V> interseccion(Set<V> set1, Set<V> set2) {
        Set<V> intersection = new HashSet<>();

        // Iterate over the smaller set for efficiency
        if (set1.size() < set2.size()) {
            for (V element : set1) {
                if (set2.contains(element)) {
                    intersection.add(element);
                }
            }
        } else {
            for (V element : set2) {
                if (set1.contains(element)) {
                    intersection.add(element);
                }
            }
        }

        return intersection;
    }
}

import java.util.Collection;
import java.util.ArrayList;

public class ArrayConverter {
    /**
     * Convierte la colección dada en un arreglo de Strings. El arreglo devuelto no contiene entradas <code>null</code>. 
     * Tenga en cuenta que {@link Arrays#sort(Object[])} lanzará una {@link NullPointerException} si un elemento del arreglo es <code>null</code>.
     * @param collection La colección a convertir
     * @return Un nuevo arreglo de Strings.
     */
    static String[] toNoNullStringArray(Collection<?> collection) {
        if (collection == null) {
            return new String[0];
        }

        ArrayList<String> result = new ArrayList<>();

        for (Object obj : collection) {
            if (obj != null) {
                result.add(obj.toString());
            }
        }

        return result.toArray(new String[0]);
    }
}

