import java.util.Iterator;
import java.util.ArrayList;

public class CategoryTree {
    private Category root;

    protected class Category {
        private boolean active;
        private ArrayList<Category> children;

        public Category() {
            this.active = false;
            this.children = new ArrayList<>();
        }

        public boolean isActive() {
            return active;
        }

        public ArrayList<Category> getChildren() {
            return children;
        }
    }

    protected int removeUnusedNodes() {
        if (root == null) {
            return 0;
        }
        return removeUnusedNodesRecursive(root);
    }

    private int removeUnusedNodesRecursive(Category node) {
        int count = 0;

        if (node.getChildren().isEmpty()) {
            return node.isActive() ? 0 : 1;
        }

        Iterator<Category> iterator = node.getChildren().iterator();
        while (iterator.hasNext()) {
            Category child = iterator.next();
            count += removeUnusedNodesRecursive(child);

            if (!child.isActive() && child.getChildren().isEmpty()) {
                iterator.remove();
            }
        }

        if (!node.isActive() && node.getChildren().isEmpty()) {
            count++;
        }

        return count;
    }
}

import org.objectweb.asm.Label;

public class BytecodeReader {

    /**
     * Devuelve la etiqueta correspondiente al "offset" del bytecode dado. La implementación predeterminada de este método crea una etiqueta para el desplazamiento dado si aún no se ha creado.
     * @param bytecodeOffset un "offset" de bytecode en un método.
     * @param labels las etiquetas ya creadas, indexadas por su "offset". Si ya existe una etiqueta para bytecodeOffset, este método no debe crear una nueva. De lo contrario, debe almacenar la nueva etiqueta en este arreglo.
     * @return una etiqueta no nula, que debe ser igual a labels[bytecodeOffset].
     */
    protected Label readLabel(final int bytecodeOffset, final Label[] labels) {
        Label label = labels[bytecodeOffset];
        if (label == null) {
            label = new Label();
            labels[bytecodeOffset] = label;
        }
        return label;
    }
}

public class BooleanConverter {
    /**
     * Si <code>value</code> es "true", se devuelve <code>true</code>. Si <code>value</code> es "false", se devuelve <code>false</code>. 
     * De lo contrario, se devuelve <code>default</code>.
     * El caso de <code>value</code> no es importante.
     */
    public static boolean toBoolean(String value, boolean dEfault) {
        if (value == null) {
            return dEfault;
        }

        String lowercaseValue = value.toLowerCase();

        if (lowercaseValue.equals("true")) {
            return true;
        }

        if (lowercaseValue.equals("false")) {
            return false;
        }

        return dEfault;
    }
}

public class StringUtils {
    /**
     * Elimina los espacios en blanco al inicio de la cadena dada.
     * @param str la cadena a verificar
     * @return la cadena sin espacios en blanco al inicio
     * @see java.lang.Character#isWhitespace
     */
    public static String trimLeadingWhitespace(String str) {
        if (str == null) {
            return null;
        }

        int len = str.length();
        int start = 0;

        while (start < len && Character.isWhitespace(str.charAt(start))) {
            start++;
        }

        return str.substring(start);
    }
}

import java.nio.ByteBuffer;

public class ClassReader {
    private ByteBuffer classFileBuffer;

    final String readUtf(final int constantPoolEntryIndex, final char[] charBuffer) {
        // Get the UTF8 string length
        int utfLen = classFileBuffer.getShort(constantPoolEntryIndex) & 0xFFFF;

        int strLen = 0;
        int c;
        int st = constantPoolEntryIndex + 2;
        int cc = 0;

        while (cc < utfLen) {
            c = classFileBuffer.get(st + cc) & 0xFF;
            if ((c & 0x80) == 0) {
                // 0xxxxxxx
                charBuffer[strLen++] = (char) c;
            } else if ((c & 0xE0) == 0xC0) {
                // 110xxxxx 10xxxxxx
                charBuffer[strLen++] = (char) (((c & 0x1F) << 6) + 
                    (classFileBuffer.get(st + cc + 1) & 0x3F));
                cc++;
            } else {
                // 1110xxxx 10xxxxxx 10xxxxxx
                charBuffer[strLen++] = (char) (((c & 0xF) << 12) + 
                    ((classFileBuffer.get(st + cc + 1) & 0x3F) << 6) +
                    (classFileBuffer.get(st + cc + 2) & 0x3F));
                cc += 2;
            }
            cc++;
        }

        return new String(charBuffer, 0, strLen);
    }
}

public class HexDecoder {
    /**
     * Ayudante para decodificar la mitad de un número hexadecimal a partir de una cadena.
     * @param c El carácter ASCII del número hexadecimal a decodificar. Debe estar en el rango {@code [0-9a-fA-F]}.
     * @return El valor hexadecimal representado en el carácter ASCII dado, o {@link Character#MAX_VALUE} si el carácter es inválido.
     */
    private static char decodeHexNibble(final char c) {
        // Para dígitos 0-9
        if (c >= '0' && c <= '9') {
            return (char)(c - '0');
        }

        // Para letras a-f
        if (c >= 'a' && c <= 'f') {
            return (char)(c - 'a' + 10);
        }

        // Para letras A-F
        if (c >= 'A' && c <= 'F') {
            return (char)(c - 'A' + 10);
        }

        // Carácter inválido
        return Character.MAX_VALUE;
    }
}

