public class MathUtils {
    /**
     * Calcular el factorial de $n$.
     * @param n el número de entrada
     * @return el factorial
     */
    public static long factorial(int n) {
        if (n < 0) {
            throw new IllegalArgumentException("Factorial not defined for negative numbers");
        }

        if (n == 0 || n == 1) {
            return 1;
        }

        long result = 1;
        for (int i = 2; i <= n; i++) {
            result *= i;
        }
        return result;
    }
}

import java.util.function.Predicate;

public class FaceTraversal {

    private class Node {
        // Node implementation details
    }

    private class OuterFaceCirculator {
        private Node current;

        public OuterFaceCirculator(Node node) {
            this.current = node;
        }

        public Node getNode() {
            return current;
        }

        public void next(int direction) {
            // Implementation to move to next node
        }
    }

    /**
     * Encuentra y devuelve un "circulator" al nodo en el límite del componente, que satisface el {@code predicate} o devuelve un circulador al nodo {@code stop}.
     * @param predicate la condición que debe satisfacer el nodo deseado
     * @param start el nodo desde el cual comenzar la búsqueda
     * @param stop el nodo donde finalizar la búsqueda 
     * @param dir la dirección en la que comenzar la travesía
     * @return un "circulator" al nodo que satisface el {@code predicate} o al nodo {@code stop}
     */
    private OuterFaceCirculator selectOnOuterFace(Predicate<Node> predicate, Node start, Node stop, int dir) {
        OuterFaceCirculator circulator = new OuterFaceCirculator(start);

        // Continue traversing until we find a node that satisfies the predicate or reach the stop node
        while (!predicate.test(circulator.getNode())) {
            // If we've reached the stop node without finding a match, return circulator at stop
            if (circulator.getNode() == stop) {
                return circulator;
            }

            // Move to next node in specified direction
            circulator.next(dir);
        }

        return circulator;
    }
}

import org.apache.log4j.spi.LoggingEvent;
import java.util.ArrayList;
import java.util.List;

public class LogBuffer {
    private List<LoggingEvent> buffer;
    private static final int MAX_BUFFER_SIZE = 1000;

    public LogBuffer() {
        buffer = new ArrayList<>();
    }

    /**
     * Agrega un <code>evento</code> como el último evento en el búfer.
     */
    public void add(LoggingEvent event) {
        if (event == null) {
            return;
        }

        // Remove oldest event if buffer is full
        if (buffer.size() >= MAX_BUFFER_SIZE) {
            buffer.remove(0);
        }

        // Add new event to end of buffer
        buffer.add(event);
    }
}

public class LongComparator {
    /**
     * Compara los dos valores {@code long} especificados. El signo del valor devuelto es el mismo que el de {@code ((Long) a).compareTo(b)}. <p> <b>Nota para Java 7 y versiones posteriores:</b> este método debe ser tratado como obsoleto; utiliza el método equivalente {@link Long#compare} en su lugar.
     * @param a el primer {@code long} a comparar
     * @param b el segundo {@code long} a comparar
     * @return un valor negativo si {@code a} es menor que {@code b}; un valor positivo si {@code a} es mayor que {@code b}; o cero si son iguales
     */
    private static int compareSigned(long a, long b) {
        if (a < b) {
            return -1;
        }
        if (a > b) {
            return 1;
        }
        return 0;
    }
}

