import org.objectweb.asm.Symbol;
import org.objectweb.asm.Constants;

public class SymbolTable {
    private final Symbol[] symbols;
    private int size;

    public SymbolTable(int initialCapacity) {
        this.symbols = new Symbol[initialCapacity];
        this.size = 1;
    }

    public int addConstantNameAndType(final String name, final String descriptor) {
        int hashCode = Symbol.CONSTANT_NAME_AND_TYPE_TAG + name.hashCode() * descriptor.hashCode();
        Symbol symbol = lookupSymbol(hashCode);

        if (symbol != null) {
            return symbol.index;
        }

        symbol = addConstantUtf8(name);
        int nameIndex = symbol.index;
        symbol = addConstantUtf8(descriptor); 
        int descriptorIndex = symbol.index;

        symbol = addConstant(new Symbol(size++, Symbol.CONSTANT_NAME_AND_TYPE_TAG, 
                                      nameIndex, descriptorIndex, hashCode));
        return symbol.index;
    }

    private Symbol lookupSymbol(int hashCode) {
        for (Symbol symbol : symbols) {
            if (symbol != null && symbol.hashCode == hashCode) {
                return symbol;
            }
        }
        return null;
    }

    private Symbol addConstant(Symbol symbol) {
        if (size >= symbols.length) {
            Symbol[] newSymbols = new Symbol[symbols.length * 2];
            System.arraycopy(symbols, 0, newSymbols, 0, symbols.length);
            symbols = newSymbols;
        }
        symbols[size] = symbol;
        return symbol;
    }

    private Symbol addConstantUtf8(String value) {
        int hashCode = Symbol.CONSTANT_UTF8_TAG + value.hashCode();
        Symbol symbol = lookupSymbol(hashCode);
        if (symbol != null) {
            return symbol;
        }
        return addConstant(new Symbol(size++, Symbol.CONSTANT_UTF8_TAG, value, hashCode));
    }
}

import java.util.regex.Pattern;
import java.util.regex.Matcher;

public class DotUtils {

    /**
     * Remueve el "escape" de un identificador de cadena DOT.
     * @param input la entrada
     * @return la salida sin carácteres "escape"
     */
    private String unescapeId(String input) {
        if (input == null || input.isEmpty()) {
            return input;
        }

        // Remove quotes if present at start/end
        if (input.startsWith("\"") && input.endsWith("\"")) {
            input = input.substring(1, input.length() - 1);
        }

        // Replace escaped characters
        StringBuilder result = new StringBuilder();
        Pattern pattern = Pattern.compile("\\\\(.)");
        Matcher matcher = pattern.matcher(input);

        int lastEnd = 0;
        while (matcher.find()) {
            result.append(input.substring(lastEnd, matcher.start()));
            result.append(matcher.group(1));
            lastEnd = matcher.end();
        }
        result.append(input.substring(lastEnd));

        return result.toString();
    }
}

public class ArrayUtils {
    /**
     * Concatenar los arreglos de cadenas dados en uno solo, incluyendo los elementos de los arreglos que se superponen dos veces.
     * El orden de los elementos en los arreglos originales se preserva.
     * @param array1 el primer arreglo (puede ser <code>null</code>)
     * @param array2 el segundo arreglo (puede ser <code>null</code>) 
     * @return el nuevo arreglo (<code>null</code> si ambos arreglos dados eran <code>null</code>)
     */
    public static String[] concatenateStringArrays(String[] array1, String[] array2) {
        // Si ambos arrays son null, retornar null
        if (array1 == null && array2 == null) {
            return null;
        }

        // Si uno de los arrays es null, retornar una copia del otro
        if (array1 == null) {
            return array2.clone();
        }
        if (array2 == null) {
            return array1.clone();
        }

        // Crear nuevo array con la suma de las longitudes
        String[] result = new String[array1.length + array2.length];

        // Copiar elementos del primer array
        System.arraycopy(array1, 0, result, 0, array1.length);

        // Copiar elementos del segundo array
        System.arraycopy(array2, 0, result, array1.length, array2.length);

        return result;
    }
}

import java.util.*;

public class LabelPropagation {

    /**
     * Mueve todos los vértices del cubo con etiqueta {@code minLabel} al cubo con etiqueta 0. 
     * Limpia el cubo con etiqueta {@code minLabel}. Actualiza el etiquetado en consecuencia.
     * @param bucketsByLabel los cubos donde se almacenan los vértices
     * @param labels las etiquetas de los vértices
     * @param minLabel el valor mínimo del cubo no vacío
     */
    private void reload(List<Set<Integer>> bucketsByLabel, List<Integer> labels, int minLabel) {
        // Obtener el conjunto de vértices del cubo minLabel
        Set<Integer> vertices = bucketsByLabel.get(minLabel);

        // Mover cada vértice al cubo 0
        for (Integer vertex : vertices) {
            // Actualizar la etiqueta del vértice a 0
            labels.set(vertex, 0);

            // Agregar el vértice al cubo 0
            bucketsByLabel.get(0).add(vertex);
        }

        // Limpiar el cubo minLabel
        bucketsByLabel.get(minLabel).clear();
    }
}

import java.util.Arrays;

public class ArrayUtils {
    /**
     * Agrega la cadena dada al arreglo de cadenas proporcionado, devolviendo un nuevo arreglo que consiste en el contenido del arreglo de entrada más la cadena dada.
     * @param array el arreglo al que se va a agregar (puede ser <code>null</code>)
     * @param str la cadena a agregar
     * @return el nuevo arreglo (nunca <code>null</code>)
     */
    public static String[] addStringToArray(String[] array, String str) {
        if (array == null) {
            return new String[] { str };
        }

        String[] newArray = Arrays.copyOf(array, array.length + 1);
        newArray[array.length] = str;
        return newArray;
    }
}

public class StringUtils {

    /** 
     * Devuelve el número de ocurrencias de la subcadena {@code sub} en la cadena {@code str}.
     * @param str cadena en la que buscar. Devuelve 0 si es nula.
     * @param sub cadena a buscar. Devuelve 0 si es nula.
     * @return el número de ocurrencias de la subcadena {@code sub} en la cadena {@code str}.
     */
    public static int countOccurrencesOf(String str, String sub) {
        if (str == null || sub == null || sub.length() == 0) {
            return 0;
        }

        int count = 0;
        int pos = 0;
        int idx;

        while ((idx = str.indexOf(sub, pos)) != -1) {
            count++;
            pos = idx + sub.length();
        }

        return count;
    }
}

import org.atmosphere.cpr.AtmosphereInterceptor;
import java.util.List;

public class InterceptorChecker {

    /** 
     * <p> Verifica en la lista especificada si hay al menos una instancia de la clase de implementación del {@link AtmosphereInterceptor interceptor} dado.</p>
     * @param interceptorList los interceptores
     * @param c               la clase del interceptor
     * @return {@code false} si ya existe una instancia de la clase en la lista, {@code true} en caso contrario
     */
    private boolean checkDuplicate(final List<AtmosphereInterceptor> interceptorList, Class<? extends AtmosphereInterceptor> c) {
        if (interceptorList == null || c == null) {
            return false;
        }

        for (AtmosphereInterceptor interceptor : interceptorList) {
            if (c.isAssignableFrom(interceptor.getClass())) {
                return false;
            }
        }
        return true;
    }
}

