import java.util.NoSuchElementException;

public class LinkedList<E> {

    private class ListNodeImpl<T> {
        T element;
        ListNodeImpl<T> next;
        ListNodeImpl<T> prev;

        ListNodeImpl(T element, ListNodeImpl<T> prev, ListNodeImpl<T> next) {
            this.element = element;
            this.prev = prev;
            this.next = next;
        }
    }

    private ListNodeImpl<E> first;
    private ListNodeImpl<E> last;
    private int size;

    private boolean unlink(ListNodeImpl<E> node) {
        if (node == null) {
            return false;
        }

        final ListNodeImpl<E> prev = node.prev;
        final ListNodeImpl<E> next = node.next;

        if (prev == null) {
            // Node is the first element
            first = next;
        } else {
            prev.next = next;
            node.prev = null;
        }

        if (next == null) {
            // Node is the last element
            last = prev; 
        } else {
            next.prev = prev;
            node.next = null;
        }

        node.element = null;
        size--;
        return true;
    }
}

import java.util.ArrayList;
import java.util.List;

public class SequenceRangeBuilder {

    private static class SequenceRange {
        private int start;
        private int end;

        public SequenceRange(int start, int end) {
            this.start = start;
            this.end = end;
        }

        public int getStart() {
            return start;
        }

        public int getEnd() {
            return end;
        }
    }

    public List<SequenceRange> buildSequenceRanges() {
        List<SequenceRange> ranges = new ArrayList<>();

        // Assuming we have a list of profiles with sequence numbers
        List<Integer> profileSequences = getProfileSequences();

        if (profileSequences.isEmpty()) {
            return ranges;
        }

        // Sort sequences
        profileSequences.sort(null);

        int rangeStart = profileSequences.get(0);
        int prev = rangeStart;

        for (int i = 1; i < profileSequences.size(); i++) {
            int current = profileSequences.get(i);

            // If there's a gap in sequence, create new range
            if (current > prev + 1) {
                ranges.add(new SequenceRange(rangeStart, prev));
                rangeStart = current;
            }

            prev = current;
        }

        // Add final range
        ranges.add(new SequenceRange(rangeStart, prev));

        return ranges;
    }

    // Helper method to get profile sequences
    private List<Integer> getProfileSequences() {
        // Implementation would depend on how profile data is stored
        return new ArrayList<>();
    }
}

