public class FileUtils {

    /**
     * Elimina la extensión del nombre de archivo de la ruta dada, por ejemplo, "mypath/myfile.txt" -> "mypath/myfile".
     * @param path la ruta del archivo (puede ser <code>null</code>)
     * @return la ruta con la extensión del nombre de archivo eliminada, o <code>null</code> si no hay ninguna
     */
    public static String stripFilenameExtension(String path) {
        if (path == null) {
            return null;
        }

        int lastDotIndex = path.lastIndexOf('.');
        if (lastDotIndex == -1) {
            return path;
        }

        int lastSeparatorIndex = path.lastIndexOf('/');
        if (lastSeparatorIndex > lastDotIndex) {
            return path;
        }

        return path.substring(0, lastDotIndex);
    }
}

package org.apache.commons.lang3;

/**
 * Utility class for Character operations
 */
public class CharacterUtils {

    /**
     * <p>Convierte un array de objetos "Character" a primitivos.</p>
     * <p>Este método devuelve <code>null</code> para un arreglo de entrada <code>null</code>.</p>
     * @param array  un arreglo de <code>Character</code>, puede ser <code>null</code>
     * @return un arreglo de <code>char</code>, <code>null</code> si el arreglo de entrada es nulo
     * @throws NullPointerException si el contenido del arreglo es <code>null</code>
     */
    public static char[] toPrimitive(final Character[] array) {
        if (array == null) {
            return null;
        }

        final char[] result = new char[array.length];
        for (int i = 0; i < array.length; i++) {
            result[i] = array[i].charValue();
        }
        return result;
    }
}

import java.util.Arrays;

public class Parser {
    private String input;
    private int currentPosition;

    /**
     * Analiza un token hasta que se encuentra con cualquiera de los terminadores dados.
     * @param terminators el arreglo de caracteres terminadores. Cualquiera de estos caracteres, al ser encontrado, indica el final del token.
     * @return el token
     */
    private String parseToken(final char[] terminators) {
        StringBuilder token = new StringBuilder();

        while (currentPosition < input.length()) {
            char currentChar = input.charAt(currentPosition);

            // Check if current character is a terminator
            if (Arrays.binarySearch(terminators, currentChar) >= 0) {
                break;
            }

            token.append(currentChar);
            currentPosition++;
        }

        return token.toString();
    }
}

public class StringUtils {
    /**
     * Elimina todas las ocurrencias del carácter inicial proporcionado de la cadena dada.
     * @param str la cadena a verificar
     * @param leadingCharacter el carácter inicial que se debe eliminar
     * @return la cadena sin el carácter inicial
     */
    public static String trimLeadingCharacter(String str, char leadingCharacter) {
        if (str == null || str.isEmpty()) {
            return str;
        }

        int i = 0;
        while (i < str.length() && str.charAt(i) == leadingCharacter) {
            i++;
        }

        return str.substring(i);
    }
}

