     * @param array1 el primer arreglo, puede ser <code>null</code>
     * @param array2 el segundo arreglo, puede ser <code>null</code>
     * @return <code>true</code> si la longitud de los arreglos coincide, tratando <code>null</code> como un arreglo vacío
     */
    public static boolean isSameLength(final double[] array1, final double[] array2) {
        int length1 = (array1 == null) ? 0 : array1.length;
        int length2 = (array2 == null) ? 0 : array2.length;
        return length1 == length2;
    }
}

import javax.servlet.http.HttpServletRequest;
import org.atmosphere.cpr.AtmosphereResource;
import org.atmosphere.cpr.Meteor;

public class MeteorLookup {

    /**
     * Recupera una instancia de {@link Meteor} basada en el {@link HttpServletRequest}.
     * @param r {@link HttpServletRequest}
     * @return un {@link Meteor} o null si no se encuentra
     */
    public static Meteor lookup(HttpServletRequest r) {
        if (r == null) {
            return null;
        }

        try {
            // Intenta obtener el Meteor desde el request
            Meteor meteor = Meteor.build(r);

            if (meteor != null) {
                AtmosphereResource resource = meteor.getAtmosphereResource();
                if (resource != null && !resource.isCancelled()) {
                    return meteor;
                }
            }

            // Si no se encuentra o está cancelado, retorna null
            return null;

        } catch (Exception e) {
            // En caso de error retorna null
            return null;
        }
    }
}

public class StringSplitter {

    /** 
     * Divide una cadena en la primera ocurrencia del delimitador. No incluye el delimitador en el resultado.
     * @param toSplit la cadena a dividir
     * @param delimiter el delimitador para dividir la cadena
     * @return un array de dos elementos donde el índice 0 es antes del delimitador, y el índice 1 es después del delimitador (ninguno de los elementos incluye el delimitador); o <code>null</code> si no se encontró el delimitador en la cadena de entrada dada
     */
    public static String[] split(String toSplit, String delimiter) {
        if (toSplit == null || delimiter == null) {
            return null;
        }

        int index = toSplit.indexOf(delimiter);

        if (index == -1) {
            return null;
        }

        String[] result = new String[2];
        result[0] = toSplit.substring(0, index);
        result[1] = toSplit.substring(index + delimiter.length());

        return result;
    }
}

import java.util.*;
import org.apache.commons.lang3.tuple.Pair;

public class SeparatorComputer {

    private Graph<V,E> graph; // Graph instance variable

    private List<Pair<List<Pair<Integer,Integer>>,E>> computeGlobalSeparatorList() {
        List<Pair<List<Pair<Integer,Integer>>,E>> globalSeparators = new ArrayList<>();

        // Iterate through all edges in the graph
        for (E edge : graph.edgeSet()) {
            // Get vertices incident to edge
            V source = graph.getEdgeSource(edge);
            V target = graph.getEdgeTarget(edge);

            // Get neighborhood subgraph around edge
            Set<V> neighborhood = new HashSet<>();
            neighborhood.add(source);
            neighborhood.add(target);
            neighborhood.addAll(Graphs.neighborListOf(graph, source));
            neighborhood.addAll(Graphs.neighborListOf(graph, target));

            Graph<V,E> subgraph = new AsSubgraph<>(graph, neighborhood);

            // Find minimal separators in neighborhood
            List<Pair<Integer,Integer>> separators = findMinimalSeparators(subgraph, source, target);

            // Add separators with associated edge to global list
            globalSeparators.add(Pair.of(separators, edge));
        }

        return globalSeparators;
    }

    // Helper method to find minimal separators between two vertices
    private List<Pair<Integer,Integer>> findMinimalSeparators(Graph<V,E> graph, V source, V target) {
        List<Pair<Integer,Integer>> separators = new ArrayList<>();

        // Use max flow / min cut to find minimal separators
        EdmondsKarpMFImpl<V,E> maxFlow = new EdmondsKarpMFImpl<>(graph);

        // Convert vertices to integers for pair representation
        int s = graph.vertexSet().indexOf(source);
        int t = graph.vertexSet().indexOf(target);

        // Find minimal separator
        Set<E> minCut = maxFlow.getMinCut(source, target);

        // Convert cut edges to vertex pairs
        for (E edge : minCut) {
            V v1 = graph.getEdgeSource(edge);
            V v2 = graph.getEdgeTarget(edge);
            separators.add(Pair.of(
                graph.vertexSet().indexOf(v1),
                graph.vertexSet().indexOf(v2)
            ));
        }

        return separators;
    }
}

