        }
    }
}

import javax.swing.*;
import java.awt.*;
import javax.swing.table.TableModel;

public class TableUtils {
    /**
     * Selecciona la fila especificada en el JTable indicado y desplaza el JScrollPane especificado hacia la fila recién seleccionada. 
     * Más importante aún, la llamada a repaint() se retrasa lo suficiente para que la tabla pinte correctamente la fila recién seleccionada, 
     * que puede estar fuera de la pantalla.
     * @param table debe pertenecer al JScrollPane especificado
     */
    public static void selectRow(int row, JTable table, JScrollPane pane) {
        if (row < 0 || row >= table.getRowCount()) {
            return;
        }

        // Seleccionar la fila
        table.setRowSelectionInterval(row, row);

        // Calcular el rectángulo de la fila seleccionada
        Rectangle rect = table.getCellRect(row, 0, true);

        // Hacer scroll hasta la fila seleccionada
        pane.getViewport().setViewPosition(new Point(0, rect.y));

        // Retrasar el repaint para asegurar que la tabla se actualice correctamente
        SwingUtilities.invokeLater(new Runnable() {
            @Override
            public void run() {
                table.repaint();
            }
        });
    }
}

import java.util.Arrays;

public class ByteVector {
    private byte[] bytes;
    private int size;
    private static final int INT_SIZE = 4;

    public ByteVector() {
        bytes = new byte[10];
        size = 0;
    }

    public ByteVector putInt(final int intValue) {
        ensureCapacity(size + INT_SIZE);

        // Store int value in big-endian format
        bytes[size] = (byte) ((intValue >> 24) & 0xFF);
        bytes[size + 1] = (byte) ((intValue >> 16) & 0xFF); 
        bytes[size + 2] = (byte) ((intValue >> 8) & 0xFF);
        bytes[size + 3] = (byte) (intValue & 0xFF);

        size += INT_SIZE;
        return this;
    }

    private void ensureCapacity(int minCapacity) {
        if (minCapacity > bytes.length) {
            int newCapacity = Math.max(bytes.length * 2, minCapacity);
            bytes = Arrays.copyOf(bytes, newCapacity);
        }
    }
}

public class ArrayUtils {
    /**
     * Compara los <code>count</code> primeros bytes en los arreglos <code>a</code> y <code>b</code>.
     * @param a     El primer arreglo a comparar.
     * @param b     El segundo arreglo a comparar. 
     * @param count Cuántos bytes se deben comparar.
     * @return <code>true</code> si los <code>count</code> primeros bytes en los arreglos <code>a</code> y <code>b</code> son iguales.
     */
    public static boolean arrayequals(byte[] a, byte[] b, int count) {
        // Check for null arrays
        if (a == null || b == null) {
            return false;
        }

        // Check if count is valid
        if (count < 0 || count > a.length || count > b.length) {
            return false;
        }

        // Compare the first count bytes
        for (int i = 0; i < count; i++) {
            if (a[i] != b[i]) {
                return false;
            }
        }

        return true;
    }
}

import java.lang.StringBuffer;

public class NameAbbreviator {

    /**
     * Abreviar nombre.
     * @param buf buffer para agregar la abreviatura.
     * @param nameStart inicio del nombre a abreviar.
     */
    public void abbreviate(final int nameStart, final StringBuffer buf) {
        if (buf == null || nameStart < 0 || nameStart >= buf.length()) {
            return;
        }

        // Find first letter and capitalize it
        char firstChar = Character.toUpperCase(buf.charAt(nameStart));

        // Replace rest of name with a period
        buf.setLength(nameStart + 2);
        buf.setCharAt(nameStart, firstChar);
        buf.setCharAt(nameStart + 1, '.');
    }
}

import java.lang.reflect.Type;
import java.lang.reflect.TypeVariable;
import java.lang.reflect.WildcardType;
import java.lang.reflect.ParameterizedType;

public class TypeResolver {

    /**
     * Resuelve el primer límite para el {@code typeVariable},
     * devolviendo {@code Unknown.class} si no se puede resolver ninguno.
     */
    public static Type resolveBound(TypeVariable<?> typeVariable) {
        Type[] bounds = typeVariable.getBounds();

        if (bounds == null || bounds.length == 0) {
            return Unknown.class;
        }

        Type bound = bounds[0];

        if (bound instanceof TypeVariable) {
            return resolveBound((TypeVariable<?>) bound);
        }

        if (bound instanceof ParameterizedType) {
            return ((ParameterizedType) bound).getRawType();
        }

        if (bound instanceof WildcardType) {
            Type[] upperBounds = ((WildcardType) bound).getUpperBounds();
            if (upperBounds != null && upperBounds.length > 0) {
                return upperBounds[0];
            }
            return Unknown.class;
        }

        if (bound instanceof Class) {
            return bound;
        }

        return Unknown.class;
    }

    private static class Unknown {
        private Unknown() {}
    }
}

import org.jgrapht.Graph;
import java.util.Set;

public class GraphUtils {

    /**
     * Verifica si el subgrafo de <code>graph</code> inducido por los <code>vertices</code> dados es completo, es decir, un clique.
     * @param graph el grafo.
     * @param vertices los vértices de los que se inducirá el subgrafo.
     * @return true si el subgrafo inducido es un clique.
     */
    private static <V,E> boolean isClique(Graph<V,E> graph, Set<V> vertices) {
        // Para cada par de vértices distintos en el conjunto
        for (V v1 : vertices) {
            for (V v2 : vertices) {
                // Si son el mismo vértice, continuamos
                if (v1.equals(v2)) {
                    continue;
                }
                // Si no existe una arista entre ellos, no es un clique
                if (!graph.containsEdge(v1, v2)) {
                    return false;
                }
            }
        }
        // Si llegamos aquí, todos los vértices están conectados entre sí
        return true;
    }
}

import java.util.ArrayList;
import java.util.List;
import java.util.Collections;

public class BoundCalculator<K extends Comparable<K>> {

    /**
     * Encuentra un límite inferior máximo para cada llave.
     * @param keys lista de llaves.
     * @return los límites inferiores de llaves calculados.
     */
    private List<Integer> computeLowerBounds(List<K> keys) {
        if (keys == null || keys.isEmpty()) {
            return new ArrayList<>();
        }

        List<Integer> lowerBounds = new ArrayList<>(keys.size());

        // Para cada llave, encontrar su límite inferior
        for (int i = 0; i < keys.size(); i++) {
            K currentKey = keys.get(i);
            int lowerBound = -1;

            // Buscar el elemento más grande que sea menor que la llave actual
            for (int j = 0; j < i; j++) {
                if (keys.get(j).compareTo(currentKey) < 0) {
                    lowerBound = Math.max(lowerBound, j);
                }
            }

            lowerBounds.add(lowerBound);
        }

        return lowerBounds;
    }
}

import java.util.Stack;

public class FrameStackHandler {
    private Stack<Object> frameStack;

    public FrameStackHandler() {
        this.frameStack = new Stack<>();
    }

    /**
     * Extrae tantos tipos abstractos de la "frame stack" de salida como lo describe el descriptor dado.
     * @param descriptor un descriptor de tipo o método (en cuyo caso se extraen sus tipos de argumento).
     */
    private void pop(final String descriptor) {
        int index = 0;
        while (index < descriptor.length()) {
            char c = descriptor.charAt(index);
            switch (c) {
                case '(':
                    // Skip opening parenthesis for method descriptors
                    index++;
                    continue;
                case ')':
                    // End of method parameters
                    return;
                case 'B':
                case 'C':
                case 'I':
                case 'S':
                case 'Z':
                case 'F':
                    // Pop single-slot types
                    frameStack.pop();
                    index++;
                    break;
                case 'J':
                case 'D':
                    // Pop double-slot types
                    frameStack.pop();
                    frameStack.pop();
                    index++;
                    break;
                case 'L':
                    // Skip reference type name until semicolon
                    frameStack.pop();
                    index = descriptor.indexOf(';', index) + 1;
                    break;
                case '[':
                    // Skip array dimensions
                    while (descriptor.charAt(index) == '[') {
                        index++;
                    }
                    if (descriptor.charAt(index) == 'L') {
                        index = descriptor.indexOf(';', index) + 1;
                    } else {
                        index++;
                    }
                    frameStack.pop();
                    break;
                default:
                    throw new IllegalArgumentException("Invalid descriptor: " + descriptor);
            }
        }
    }
}

package org.apache.commons.lang3;

public class CharUtils {
    /**
     * <p>Verifica si el carácter es ASCII de 7 bits.</p>
     * <pre>
     * CharUtils.isAscii('a')  = true
     * CharUtils.isAscii('A')  = true 
     * CharUtils.isAscii('3')  = true
     * CharUtils.isAscii('-')  = true
     * CharUtils.isAscii('\n') = true
     * CharUtils.isAscii('&copy;') = false
     * </pre>
     * @param ch el carácter a verificar
     * @return true si es menor que 128
     */
    public static boolean isAscii(final char ch) {
        return ch < 128;
    }
}

import java.util.ArrayList;
import java.util.List;

public class BPlusTree<K extends Comparable<K>> {

    private List<Integer> computeUpperBounds(List<K> keys) {
        List<Integer> upperBounds = new ArrayList<>();

        if (keys == null || keys.isEmpty()) {
            return upperBounds;
        }

        // Initialize first upper bound
        upperBounds.add(0);

        // Compare each adjacent pair of keys
        for (int i = 1; i < keys.size(); i++) {
            K currentKey = keys.get(i);
            K previousKey = keys.get(i-1);

            // If keys are equal, use same upper bound
            if (currentKey.compareTo(previousKey) == 0) {
                upperBounds.add(upperBounds.get(i-1));
            }
            // If keys are different, increment upper bound
            else {
                upperBounds.add(upperBounds.get(i-1) + 1);
            }
        }

        return upperBounds;
    }
}

import java.util.Objects;

public class TemplateEncoder {

    /**
     * Codifica una cadena con nombres de parámetros de plantilla presentes, específicamente los caracteres '{' y '}' serán codificados en formato percentil.
     * @param s la cadena con cero o más nombres de parámetros de plantilla
     * @return la cadena con los nombres de parámetros de plantilla codificados.
     */
    public static String encodeTemplateNames(String s) {
        if (s == null) {
            return null;
        }

        // Replace '{' with '%7B' and '}' with '%7D'
        return s.replace("{", "%7B")
                .replace("}", "%7D");
    }
}

import java.awt.geom.Point2D;

public class PointComparator {
    /**
     * Compara dos puntos para verificar su igualdad utilizando una tolerancia de 1e-9.
     * @param p1 el primer punto
     * @param p2 el segundo punto
     * @return si los dos puntos son iguales o no
     */
    public static boolean equals(Point2D p1, Point2D p2) {
        if (p1 == null || p2 == null) {
            return false;
        }

        double tolerance = 1e-9;
        double deltaX = Math.abs(p1.getX() - p2.getX());
        double deltaY = Math.abs(p1.getY() - p2.getY());

        return deltaX <= tolerance && deltaY <= tolerance;
    }
}

