import java.io.File;
import java.nio.file.Path;
import java.nio.file.Paths;

public class PathUtils {

    /**
     * Aplica la ruta relativa dada a la ruta proporcionada, asumiendo la separación estándar de carpetas en Java (es decir, separadores "/").
     * @param path la ruta desde la cual comenzar (generalmente una ruta de archivo completa)
     * @param relativePath la ruta relativa a aplicar (en relación con la ruta de archivo completa anterior)
     * @return la ruta de archivo completa que resulta de aplicar la ruta relativa
     */
    public static String applyRelativePath(String path, String relativePath) {
        // Normalizar los separadores de ruta
        path = path.replace('\\', '/');
        relativePath = relativePath.replace('\\', '/');

        // Si la ruta relativa comienza con /, la tratamos como ruta absoluta
        if (relativePath.startsWith("/")) {
            return relativePath;
        }

        // Dividir la ruta en componentes
        String[] pathComponents = path.split("/");
        String[] relativeComponents = relativePath.split("/");

        // Crear una lista para almacenar los componentes finales
        java.util.ArrayList<String> finalComponents = new java.util.ArrayList<>();

        // Agregar los componentes de la ruta base
        for (String component : pathComponents) {
            if (!component.isEmpty()) {
                finalComponents.add(component);
            }
        }

        // Procesar los componentes relativos
        for (String component : relativeComponents) {
            if (component.equals("..")) {
                if (!finalComponents.isEmpty()) {
                    finalComponents.remove(finalComponents.size() - 1);
                }
            } else if (!component.equals(".") && !component.isEmpty()) {
                finalComponents.add(component);
            }
        }

        // Construir la ruta final
        StringBuilder result = new StringBuilder();

        // Agregar el separador inicial si la ruta original comenzaba con uno
        if (path.startsWith("/")) {
            result.append("/");
        }

        // Unir los componentes con separadores
        for (int i = 0; i < finalComponents.size(); i++) {
            result.append(finalComponents.get(i));
            if (i < finalComponents.size() - 1) {
                result.append("/");
            }
        }

        return result.toString();
    }
}

package org.apache.commons.lang3;

public class StringUtils {
    /**
     * Encuentra el primer índice dentro de una cadena, manejando <code>null</code>. 
     * Este método utiliza {@link String#indexOf(String)}.
     *
     * @param str la cadena a verificar, puede ser null
     * @param searchStr la cadena a buscar, puede ser null
     * @return el primer índice de searchStr en str, -1 si no se encuentra o si str o searchStr son null
     */
    public static int indexOf(String str, String searchStr) {
        if (str == null || searchStr == null) {
            return -1;
        }
        return str.indexOf(searchStr);
    }
}

import java.util.ArrayList;
import java.util.List;

public class ArrayUtils {
    /**
     * Devuelve un nuevo arreglo de Strings sin elementos nulos. Método interno utilizado para normalizar listas de exclusión (arreglo y colecciones). 
     * Tenga en cuenta que {@link Arrays#sort(Object[])} lanzará un {@link NullPointerException} si un elemento del arreglo es <code>null</code>.
     * @param array El arreglo a verificar
     * @return El arreglo dado o un nuevo arreglo sin nulos.
     */
    static String[] toNoNullStringArray(Object[] array) {
        if (array == null) {
            return new String[0];
        }

        List<String> result = new ArrayList<>();

        for (Object obj : array) {
            if (obj != null) {
                result.add(obj.toString());
            }
        }

        return result.toArray(new String[0]);
    }
}

public class FilenameUtils {

    private static final char EXTENSION_SEPARATOR = '.';
    private static final char UNIX_SEPARATOR = '/';
    private static final char WINDOWS_SEPARATOR = '\\';

    /**
     * Devuelve el índice del último carácter separador de extensión, que es un punto.
     * Este método también verifica que no haya un separador de directorio después del último punto.
     * Para hacer esto, utiliza {@link #indexOfLastSeparator(String)}, que manejará un archivo en formato Unix o Windows.
     * La salida será la misma independientemente de la máquina en la que se ejecute el código.
     * 
     * @param filename el nombre del archivo en el que encontrar el último separador de ruta, null devuelve -1
     * @return el índice del último carácter separador, o -1 si no existe tal carácter
     */
    public static int indexOfExtension(String filename) {
        if (filename == null) {
            return -1;
        }

        int extensionPos = filename.lastIndexOf(EXTENSION_SEPARATOR);
        int lastSeparator = indexOfLastSeparator(filename);

        // Retorna -1 si no hay punto o si el último punto está antes del último separador
        return (extensionPos > lastSeparator) ? extensionPos : -1;
    }

    /**
     * Método auxiliar para encontrar el último separador de directorio
     */
    private static int indexOfLastSeparator(String filename) {
        if (filename == null) {
            return -1;
        }

        int lastUnixPos = filename.lastIndexOf(UNIX_SEPARATOR);
        int lastWindowsPos = filename.lastIndexOf(WINDOWS_SEPARATOR);
        return Math.max(lastUnixPos, lastWindowsPos);
    }
}

import java.time.Instant;

public class CacheMetric {
    private long lastUpdateTime;

    /**
     * @param timestamp        del tiempo actual
     * @param expiredThreshold representa la duración entre el último tiempo de actualización y el punto en el tiempo que se eliminará de la caché.
     * @return true significa que esta métrica debe ser eliminada de la caché.
     */
    public boolean isExpired(long timestamp, long expiredThreshold) {
        if (timestamp < 0 || expiredThreshold < 0) {
            throw new IllegalArgumentException("Timestamp and threshold must be non-negative values");
        }

        long timeDifference = timestamp - lastUpdateTime;
        return timeDifference >= expiredThreshold;
    }
}

import java.util.*;

public class Graph {
    private List<Node> nodes;
    private List<Edge> edges;
    private Node currentNode;
    private Iterator<Node> nodeIterator;

    public Graph() {
        nodes = new ArrayList<>();
        edges = new ArrayList<>();
        nodeIterator = nodes.iterator();
    }

    public Edge edgeToNext() {
        if (currentNode == null || !nodeIterator.hasNext()) {
            return null;
        }

        Node nextNode = nodeIterator.next();

        // Get real nodes if virtual
        Node realCurrent = currentNode.isVirtual() ? currentNode.getRealNode() : currentNode;
        Node realNext = nextNode.isVirtual() ? nextNode.getRealNode() : nextNode;

        // Find edge connecting the nodes
        for (Edge edge : edges) {
            if ((edge.getSource() == realCurrent && edge.getTarget() == realNext) ||
                (edge.getSource() == realNext && edge.getTarget() == realCurrent)) {
                currentNode = nextNode;
                return edge;
            }
        }

        currentNode = nextNode;
        return null;
    }

    // Supporting classes
    private class Node {
        private boolean isVirtual;
        private Node realNode;

        public boolean isVirtual() {
            return isVirtual;
        }

        public Node getRealNode() {
            return realNode;
        }
    }

    private class Edge {
        private Node source;
        private Node target;

        public Node getSource() {
            return source;
        }

        public Node getTarget() {
            return target;
        }
    }
}

public class StringUtils {
    /**
     * Devuelve {@code true} si la cadena dada coincide con la subcadena dada en el índice especificado, {@code false} en caso contrario.
     * @param str la cadena original (o StringBuilder)
     * @param index el índice en la cadena original para comenzar a comparar
     * @param substring la subcadena para comparar en el índice dado
     * @return {@code true} si la cadena dada coincide con la subcadena dada en el índice especificado, {@code false} en caso contrario.
     */
    public static boolean substringMatch(CharSequence str, int index, CharSequence substring) {
        if (str == null || substring == null) {
            return false;
        }

        // Check if index is out of bounds
        if (index < 0 || index + substring.length() > str.length()) {
            return false;
        }

        // Compare each character
        for (int i = 0; i < substring.length(); i++) {
            if (str.charAt(index + i) != substring.charAt(i)) {
                return false;
            }
        }

        return true;
    }
}

import org.apache.log4j.AppenderSkeleton;
import org.apache.log4j.spi.LoggingEvent;
import java.io.IOException;
import java.io.PrintWriter;
import java.net.Socket;
import java.util.ArrayList;
import java.util.List;

public class SocketAppender extends AppenderSkeleton {

    private List<Socket> connectedClients;
    private List<PrintWriter> clientWriters;

    public SocketAppender() {
        connectedClients = new ArrayList<>();
        clientWriters = new ArrayList<>();
    }

    @Override
    protected void append(LoggingEvent event) {
        String message = layout.format(event);

        // Iterate through all connected clients and send the message
        for (int i = clientWriters.size() - 1; i >= 0; i--) {
            try {
                PrintWriter writer = clientWriters.get(i);
                writer.println(message);
                writer.flush();
            } catch (Exception e) {
                // If there's an error writing to client, remove them from the list
                removeClient(i);
            }
        }
    }

    public void addClient(Socket client) throws IOException {
        connectedClients.add(client);
        clientWriters.add(new PrintWriter(client.getOutputStream(), true));
    }

    private void removeClient(int index) {
        try {
            connectedClients.get(index).close();
        } catch (IOException e) {
            // Ignore close errors
        }
        connectedClients.remove(index);
        clientWriters.remove(index);
    }

    @Override
    public void close() {
        for (Socket client : connectedClients) {
            try {
                client.close();
            } catch (IOException e) {
                // Ignore close errors
            }
        }
        connectedClients.clear();
        clientWriters.clear();
    }

    @Override
    public boolean requiresLayout() {
        return true;
    }
}

package org.apache.commons.lang3;

/**
 * Utility class for working with characters.
 */
public class CharUtils {

    /**
     * Array of String values for characters with ASCII values 0-127.
     * Used for caching common single character String values.
     */
    private static final String[] CHAR_STRING_ARRAY = new String[128];

    /**
     * Initialize the ASCII character cache
     */
    static {
        for (int i = 0; i < CHAR_STRING_ARRAY.length; i++) {
            CHAR_STRING_ARRAY[i] = String.valueOf((char) i);
        }
    }

    /**
     * <p>Convierte el carácter en una cadena que contiene un solo carácter.</p>
     * <p>Para caracteres ASCII de 7 bits, utiliza una caché que devolverá el mismo 
     * objeto String cada vez.</p>
     * 
     * <pre>
     * CharUtils.toString(' ')  = " "
     * CharUtils.toString('A')  = "A"
     * </pre>
     *
     * @param ch  el carácter a convertir
     * @return una cadena que contiene el carácter especificado
     */
    public static String toString(final char ch) {
        if (ch < 128) {
            return CHAR_STRING_ARRAY[ch];
        }
        return String.valueOf(ch);
    }
}

import java.io.IOException;

public class FieldReader {
    private boolean isPackedField = false;
    private int currentPosition = 0;
    private byte[] buffer;
    private static final byte PACKED_FIELD_MARKER = 0x1C;

    /**
     * Verifica si este campo ha sido empaquetado en un campo delimitado por longitud. 
     * Si es así, actualiza el estado interno para reflejar que se están leyendo campos empaquetados.
     * @throws IOException si hay un error al leer el buffer
     */
    private void checkIfPackedField() throws IOException {
        if (currentPosition >= buffer.length) {
            throw new IOException("Buffer overflow - unable to check for packed field");
        }

        if (buffer[currentPosition] == PACKED_FIELD_MARKER) {
            isPackedField = true;
            currentPosition++; // Skip the packed field marker

            // Read the length bytes
            int length = 0;
            while (currentPosition < buffer.length && 
                   Character.isDigit((char)buffer[currentPosition])) {
                length = length * 10 + (buffer[currentPosition] - '0');
                currentPosition++;
            }

            if (currentPosition >= buffer.length || length <= 0) {
                throw new IOException("Invalid packed field format");
            }
        }
    }
}

import java.io.IOException;
import java.io.InputStream;

public class CodedInputStream {
    private final InputStream input;
    private int lastTag = 0;
    private int pos = 0;
    private byte[] buffer;
    private int bufferSize;
    private static final int BUFFER_SIZE = 4096;

    public CodedInputStream(InputStream input) {
        this.input = input;
        this.buffer = new byte[BUFFER_SIZE];
        this.bufferSize = 0;
    }

    public int readTag() throws IOException {
        if (isAtEnd()) {
            lastTag = 0;
            return 0;
        }

        lastTag = readRawVarint32();
        if (lastTag == 0) {
            // If we actually read zero, that's not a valid tag.
            throw new IOException("Invalid tag: zero is not a valid tag value");
        }
        return lastTag;
    }

    private boolean isAtEnd() throws IOException {
        if (pos < bufferSize) {
            return false;
        }

        int read = input.read(buffer, 0, BUFFER_SIZE);
        if (read <= 0) {
            return true;
        }

        pos = 0;
        bufferSize = read;
        return false;
    }

    private int readRawVarint32() throws IOException {
        int result = 0;
        int shift = 0;

        while (shift < 32) {
            byte b = readRawByte();
            result |= (b & 0x7F) << shift;
            if ((b & 0x80) == 0) {
                return result;
            }
            shift += 7;
        }
        throw new IOException("Malformed varint");
    }

    private byte readRawByte() throws IOException {
        if (pos == bufferSize) {
            int read = input.read(buffer, 0, BUFFER_SIZE);
            if (read <= 0) {
                throw new IOException("End of input");
            }
            pos = 0;
            bufferSize = read;
        }
        return buffer[pos++];
    }
}

import java.util.Arrays;

public class ByteVector {
    private byte[] data;
    private int length;
    private static final int DEFAULT_CAPACITY = 64;

    public ByteVector() {
        data = new byte[DEFAULT_CAPACITY];
        length = 0;
    }

    /**
     * Coloca dos bytes en este vector de bytes. El vector de bytes se amplía automáticamente si es necesario.
     * @param byteValue1 un byte.
     * @param byteValue2 otro byte.
     * @return este vector de bytes.
     */
    final ByteVector put11(final int byteValue1, final int byteValue2) {
        if (length + 2 > data.length) {
            data = Arrays.copyOf(data, Math.max(2 * data.length, length + 2));
        }
        data[length++] = (byte) byteValue1;
        data[length++] = (byte) byteValue2;
        return this;
    }
}

import java.util.Objects;

public class ContentRangeBuilder {

    private Long start;
    private Long end; 
    private Long total;
    private String unit = "bytes";

    /**
     * Construye el valor del encabezado HTTP 'Content-Range'.
     * @return valor de 'Content-Range'
     */
    private String buildContentRange() {
        if (Objects.isNull(start) || Objects.isNull(end) || Objects.isNull(total)) {
            return null;
        }

        StringBuilder contentRange = new StringBuilder();
        contentRange.append(unit)
                   .append(" ")
                   .append(start)
                   .append("-")
                   .append(end)
                   .append("/")
                   .append(total);

        return contentRange.toString();
    }

    // Setters for builder pattern
    public ContentRangeBuilder setStart(Long start) {
        this.start = start;
        return this;
    }

    public ContentRangeBuilder setEnd(Long end) {
        this.end = end;
        return this;
    }

    public ContentRangeBuilder setTotal(Long total) {
        this.total = total;
        return this;
    }

    public ContentRangeBuilder setUnit(String unit) {
        this.unit = unit;
        return this;
    }
}

import java.io.*;
import java.util.*;

public class ThreadSnapshotParser {

    public static class ThreadSnapshot {
        private long timestamp;
        private String threadName;
        private String threadState;
        private List<String> stackTrace;

        public ThreadSnapshot(long timestamp, String threadName, String threadState, List<String> stackTrace) {
            this.timestamp = timestamp;
            this.threadName = threadName;
            this.threadState = threadState;
            this.stackTrace = stackTrace;
        }

        public long getTimestamp() {
            return timestamp;
        }
    }

    public static class ProfileAnalyzeTimeRange {
        private long startTime;
        private long endTime;

        public ProfileAnalyzeTimeRange(long startTime, long endTime) {
            this.startTime = startTime;
            this.endTime = endTime;
        }

        public boolean isInRange(long timestamp) {
            return timestamp >= startTime && timestamp <= endTime;
        }
    }

    public static List<ThreadSnapshot> parseFromFileWithTimeRange(File file, List<ProfileAnalyzeTimeRange> timeRanges) throws IOException {
        List<ThreadSnapshot> snapshots = new ArrayList<>();

        try (BufferedReader reader = new BufferedReader(new FileReader(file))) {
            String line;
            long currentTimestamp = -1;
            String currentThreadName = null;
            String currentThreadState = null;
            List<String> currentStackTrace = new ArrayList<>();

            while ((line = reader.readLine()) != null) {
                if (line.startsWith("Time:")) {
                    // If we were processing a previous snapshot, save it
                    if (currentTimestamp != -1) {
                        ThreadSnapshot snapshot = new ThreadSnapshot(
                            currentTimestamp, 
                            currentThreadName,
                            currentThreadState,
                            new ArrayList<>(currentStackTrace)
                        );

                        // Only add if timestamp is in any of the specified ranges
                        for (ProfileAnalyzeTimeRange range : timeRanges) {
                            if (range.isInRange(currentTimestamp)) {
                                snapshots.add(snapshot);
                                break;
                            }
                        }
                    }

                    // Start new snapshot
                    currentTimestamp = Long.parseLong(line.substring(5).trim());
                    currentStackTrace.clear();
                } else if (line.startsWith("Thread:")) {
                    currentThreadName = line.substring(7).trim();
                } else if (line.startsWith("State:")) {
                    currentThreadState = line.substring(6).trim();
                } else if (!line.trim().isEmpty()) {
                    currentStackTrace.add(line.trim());
                }
            }

            // Handle last snapshot
            if (currentTimestamp != -1) {
                ThreadSnapshot snapshot = new ThreadSnapshot(
                    currentTimestamp,
                    currentThreadName,
                    currentThreadState,
                    new ArrayList<>(currentStackTrace)
                );

                for (ProfileAnalyzeTimeRange range : timeRanges) {
                    if (range.isInRange(currentTimestamp)) {
                        snapshots.add(snapshot);
                        break;
                    }
                }
            }
        }

        return snapshots;
    }
}
